import numpy as np


class Rasterizer:
    def __init__(self, bb_min, bb_max, resolution, padding=(0, 0)):
        self.padding = np.array(padding)
        self.resolution = resolution
        self.padding_meter = self.padding * self.resolution
        self.bb_min = (bb_min[:2] / resolution).astype(
            int
        ) * resolution - self.padding_meter  # Align to grid
        self.bb_max = bb_max[:2] + self.padding_meter

        raster_dimensions = np.ceil(
            (self.bb_max - self.bb_min) / self.resolution
        ).astype(np.int_)
        self.width = int(raster_dimensions[0])
        self.height = int(raster_dimensions[1])

    @classmethod
    def from_pointcloud(cls, pointcloud, resolution, padding=0):
        return cls(
            pointcloud.bb_min(), pointcloud.bb_max(), resolution, padding=padding
        )

    def to_relative(self, xy, truncate=True):
        coords = (xy[:, :2] - self.bb_min) / self.resolution
        coords[:, 1] = self.height - coords[:, 1]  # Invert y axis to match raster frame
        if truncate:
            return np.floor(coords).astype(np.int_)
        return coords

    def to_absolute(self, xy):
        x_abs = self.bb_min[0] + xy[:, 0].astype(np.float64) * self.resolution
        y_abs = (
            self.bb_min[1]
            + (float(self.height) - xy[:, 1].astype(np.float64)) * self.resolution
        )
        return np.vstack((x_abs, y_abs)).T

    def filter_relative(self, xy, exclude_padding=None):
        padding = np.array((0, 0))
        if exclude_padding == "inherit":
            padding += self.padding
        elif exclude_padding:
            padding += (exclude_padding).astype(np.int_)
        return (
            ((xy[:, 0] - padding[0]) >= 0)
            & ((xy[:, 0] + padding[0]) < self.width)
            & ((xy[:, 1] - padding[1]) >= 0)
            & ((xy[:, 1] + padding[1]) < self.height)
        )

    def filter_absolute(self, xy, exclude_padding=None):
        rel_coords = self.to_relative(xy)
        return self.filter_relative(rel_coords, exclude_padding=exclude_padding)

    def create_matrix(self, channels=1, dtype=np.float32, default=0):
        dimensions = (
            (self.height, self.width)
            if channels == 1
            else (self.height, self.width, channels)
        )
        return np.full(dimensions, default, dtype=dtype)

    def get_padding_mask(self):
        mask = self.create_matrix(dtype=np.bool_, default=True)
        mask[self.padding[1] : -self.padding[1], self.padding[0] : -self.padding[0]] = (
            False
        )
        return mask

    def fill(self, xy, values, default=0, sort=None):
        if isinstance(sort, np.ndarray):
            order = sort
        elif sort == "ascend":
            order = np.argsort(values)
        elif sort == "descend":
            order = np.argsort(values)[::-1]
        else:
            order = np.arange(len(values))

        channels = 1 if len(values.shape) == 1 else values.shape[1]
        matrix = self.create_matrix(
            channels=channels, dtype=values.dtype, default=default
        )
        matrix[xy[order, 1], xy[order, 0]] = values[order]
        return matrix
